<template>
  <div class="banner-list-container">
    <el-card>
      <div class="action-container">
        <el-button type="primary" @click="handleAdd" icon="el-icon-plus">添加轮播图</el-button>
        <el-button type="danger" @click="handleBatchDelete" :disabled="!selectedItems.length">批量删除</el-button>
      </div>
      
      <el-table
        v-loading="listLoading"
        :data="list"
        border
        highlight-current-row
        @selection-change="handleSelectionChange"
      >
        <el-table-column type="selection" width="55"></el-table-column>
        <el-table-column prop="id" label="ID" width="80"></el-table-column>
        <el-table-column label="图片预览" width="150">
          <template slot-scope="scope">
            <el-image :src="scope.row.image" class="banner-image" :preview-src-list="[scope.row.image]"></el-image>
          </template>
        </el-table-column>
        <el-table-column prop="title" label="标题" min-width="150"></el-table-column>
        <el-table-column prop="link" label="链接地址" min-width="200"></el-table-column>
        <el-table-column prop="sort" label="排序" width="80"></el-table-column>
        <el-table-column prop="status" label="状态" width="100">
          <template slot-scope="scope">
            <el-tag :type="scope.row.status ? 'success' : 'info'">{{ scope.row.status ? '启用' : '禁用' }}</el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="createTime" label="创建时间" width="180"></el-table-column>
        <el-table-column label="操作" width="200">
          <template slot-scope="scope">
            <el-button size="mini" @click="handleEdit(scope.row)">编辑</el-button>
            <el-button 
              size="mini" 
              :type="scope.row.status ? 'info' : 'success'"
              @click="handleToggleStatus(scope.row)"
            >
              {{ scope.row.status ? '禁用' : '启用' }}
            </el-button>
            <el-button size="mini" type="danger" @click="handleDelete(scope.row)">删除</el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-empty v-if="!listLoading && list.length === 0" description="暂无数据" />
      
      <div class="pagination-container">
        <el-pagination
          background
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="listQuery.page"
          :page-sizes="[10, 20, 30, 50]"
          :page-size="listQuery.pageSize"
          layout="total, sizes, prev, pager, next, jumper"
          :total="total"
        ></el-pagination>
      </div>
    </el-card>
    
    <el-dialog :title="dialogStatus === 'create' ? '添加轮播图' : '编辑轮播图'" :visible.sync="dialogVisible" width="500px">
      <el-form :model="form" :rules="rules" ref="bannerForm" label-width="100px">
        <el-form-item label="标题" prop="title">
          <el-input v-model="form.title" placeholder="请输入轮播图标题"></el-input>
        </el-form-item>
        <el-form-item label="轮播图片">
          <el-upload
            class="image-uploader"
            action="#"
            :http-request="uploadImage"
            :show-file-list="false"
            :before-upload="beforeUpload"
          >
            <img v-if="form.image" :src="form.image" class="uploaded-image">
            <i v-else class="el-icon-plus avatar-uploader-icon"></i>
          </el-upload>
          <div class="upload-tip">建议尺寸：750x350像素，支持JPG、PNG格式</div>
        </el-form-item>
        <el-form-item label="链接地址" prop="link">
          <el-input v-model="form.link" placeholder="请输入跳转链接"></el-input>
        </el-form-item>
        <el-form-item label="排序" prop="sort">
          <el-input-number v-model="form.sort" :min="0" :max="999"></el-input-number>
          <div class="form-tip">数值越小越靠前</div>
        </el-form-item>
        <el-form-item label="状态">
          <el-switch v-model="form.status" :active-value="true" :inactive-value="false"></el-switch>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="dialogVisible = false">取消</el-button>
        <el-button type="primary" @click="submitForm" :loading="submitLoading">确定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import bannerApi from '@/api/banner'
import request from '@/api'

export default {
  name: 'BannerList',
  data() {
    return {
      list: [],
      total: 0,
      listLoading: true,
      listQuery: { page: 1, pageSize: 10 },
      selectedItems: [],
      dialogVisible: false,
      dialogStatus: 'create',
      submitLoading: false,
      form: {
        title: '',
        image: '',
        link: '',
        sort: 0,
        status: true
      },
      rules: {
        title: [{ required: true, message: '请输入标题', trigger: 'blur' }],
        sort: [{ type: 'number', message: '排序必须为数字', trigger: 'blur' }]
      }
    }
  },
  created() {
    this.fetchData()
  },
  methods: {
    fetchData() {
      this.listLoading = true
      bannerApi.getList(this.listQuery).then(res => {
        if (res.code === 0) {
          this.list = res.data.list || []
          this.total = res.data.total || 0
        }
        this.listLoading = false
      }).catch(() => {
        this.listLoading = false
      })
    },
    handleAdd() {
      this.dialogStatus = 'create'
      this.form = { title: '', image: '', link: '', sort: 0, status: true }
      this.dialogVisible = true
    },
    handleEdit(row) {
      this.dialogStatus = 'update'
      this.form = { ...row }
      this.dialogVisible = true
    },
    handleDelete(row) {
      this.$confirm('确定删除该轮播图？', '提示', { type: 'warning' }).then(() => {
        bannerApi.delete(row.id).then(res => {
          if (res.code === 0) {
            this.$message.success('删除成功')
            this.fetchData()
          }
        })
      })
    },
    handleBatchDelete() {
      this.$confirm('确定删除选中的轮播图？', '提示', { type: 'warning' }).then(() => {
        const ids = this.selectedItems.map(item => item.id)
        bannerApi.batchDelete(ids).then(res => {
          if (res.code === 0) {
            this.$message.success('批量删除成功')
            this.selectedItems = []
            this.fetchData()
          }
        })
      })
    },
    handleToggleStatus(row) {
      bannerApi.updateStatus(row.id, !row.status).then(res => {
        if (res.code === 0) {
          row.status = !row.status
          this.$message.success(row.status ? '已启用' : '已禁用')
        }
      })
    },
    submitForm() {
      this.$refs.bannerForm.validate(valid => {
        if (valid) {
          this.submitLoading = true
          const api = this.dialogStatus === 'create' ? bannerApi.create : bannerApi.update.bind(this, this.form.id)
          api(this.form).then(res => {
            if (res.code === 0) {
              this.$message.success(this.dialogStatus === 'create' ? '添加成功' : '修改成功')
              this.dialogVisible = false
              this.fetchData()
            }
          }).finally(() => {
            this.submitLoading = false
          })
        }
      })
    },
    uploadImage(options) {
      const formData = new FormData()
      formData.append('file', options.file)
      request({
        url: '/api/upload/image',
        method: 'post',
        data: formData,
        headers: { 'Content-Type': 'multipart/form-data' }
      }).then(res => {
        if (res.code === 0) {
          this.form.image = res.data.url
          options.success(res)
        }
      })
    },
    beforeUpload(file) {
      const types = ['image/jpeg', 'image/png']
      if (!types.includes(file.type)) {
        this.$message.error('请上传JPG或PNG格式图片')
        return false
      }
      if (file.size > 2 * 1024 * 1024) {
        this.$message.error('图片大小不能超过2MB')
        return false
      }
      return true
    },
    handleSelectionChange(val) {
      this.selectedItems = val
    },
    handleSizeChange(val) {
      this.listQuery.pageSize = val
      this.fetchData()
    },
    handleCurrentChange(val) {
      this.listQuery.page = val
      this.fetchData()
    }
  }
}
</script>

<style scoped>
.banner-image {
  width: 100px;
  height: 60px;
  object-fit: cover;
}
.image-uploader {
  display: flex;
  align-items: center;
  justify-content: center;
}
.uploaded-image {
  width: 200px;
  height: 100px;
  object-fit: cover;
}
.upload-tip {
  color: #999;
  font-size: 12px;
  margin-top: 8px;
}
</style>